import React, { useState } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { useYcmhPermissions } from '../../../hooks/useYcmhPermissions';
import { ycmhPageLabels } from '../../../constants/ycmhPageLabels';
import { useAppDispatch } from '../../../store/hooks';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { RequestLineDto } from '../../../services/mh/models';
import { DocumentFormHeader } from '../../../components/layout';
import {
  MaterialLinesGridActions,
  useMaterialLinesSelection,
  useVoucherHeaderCompact,
  VoucherDocumentFormShell,
} from '../../../components/form';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import df from '../../../styles/documentForm.module.css';
import { DEPARTMENT_FIELD_LABEL, withDepartmentPlaceholder } from '../../../utils/departmentField';

const emptyLine = (): RequestLineDto => ({
  materialCode: '',
  materialName: '',
  unitCode: '',
  quantity: 1,
  estimatedPrice: 0,
  note: '',
});

const YcmhFormPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canWrite } = useYcmhPermissions();
  const navigate = useNavigate();
  const { id: routeId } = useParams<{ id: string }>();
  const [searchParams] = useSearchParams();
  const editId = routeId && routeId !== 'them' ? routeId : searchParams.get('editId') ?? undefined;
  const isEdit = Boolean(editId);
  const isNew = !isEdit;

  const [requestDate, setRequestDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [departmentId, setDepartmentId] = useState('');
  const [description, setDescription] = useState('');
  const [lines, setLines] = useState<RequestLineDto[]>([emptyLine()]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(false);

  const { copyLine, lineRowProps } = useMaterialLinesSelection(lines, setLines);
  const compact = useVoucherHeaderCompact({
    enabled: true,
    headerExpanded,
    styles: {
      field: df.field,
      headerCompactHidden: df.headerCompactHidden,
      headerCompactActive: df.headerCompactActive,
    },
  });

  const initFormName = isEdit ? 'edit-purchase-request' : 'create-purchase-request';
  const { departmentOptions } = useVoucherInitData(initFormName);
  React.useEffect(() => {
    if (!editId) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getRequest(editId)
        .then(r => {
          if (cancelled) return;
          setRequestDate(r.requestDate?.slice(0, 10) ?? '');
          setDepartmentId(r.departmentId ?? '');
          setDescription(r.description ?? '');
          setLines(r.lines?.length ? r.lines : [emptyLine()]);
        })
        .catch(err => dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, ycmhPageLabels.loadError),
          type: 'error',
        }))
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [editId, dispatch]);

  const deptOptions = withDepartmentPlaceholder(departmentOptions);

  const updateLine = (idx: number, patch: Partial<RequestLineDto>) => {
    setLines(prev => prev.map((l, i) => (i === idx ? { ...l, ...patch } : l)));
  };

  const addLine = () => setLines(prev => [...prev, emptyLine()]);
  const removeLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: ycmhPageLabels.minLineWarning, type: 'warning' });
      return;
    }
    setLines(prev => prev.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    if (!lines.some(l => l.materialCode.trim())) {
      dispatchAppToast(dispatch, { message: ycmhPageLabels.materialLineWarning, type: 'warning' });
      return;
    }
    setSaving(true);
    try {
      const payload = {
        requestDate: new Date(requestDate).toISOString(),
        departmentId: departmentId || undefined,
        description: description || undefined,
        lines: lines.filter(l => l.materialCode.trim()),
      };
      if (isEdit && editId) {
        await purchasingService.updateRequest(editId, payload);
        dispatchAppToast(dispatch, { message: ycmhPageLabels.updateSuccess, type: 'success' });
        navigate(`/mh/ycmh/${editId}`);
      } else {
        const created = await purchasingService.createRequest(payload);
        dispatchAppToast(dispatch, { message: ycmhPageLabels.createSuccess, type: 'success' });
        navigate(`/mh/ycmh/${created.id}`);
      }
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, ycmhPageLabels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const backPath = isEdit && editId ? `/mh/ycmh/${editId}` : '/mh/ycmh';

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  const showSave = canWrite && (isNew || isEdit);

  return (
    <VoucherDocumentFormShell
      testId="erp-mh-ycmh-form"
      header={(
        <DocumentFormHeader
          onBack={() => navigate(backPath)}
          title={isEdit ? 'Sửa YCMH' : 'Tạo YCMH'}
          isNew={isNew}
          saving={saving}
          saveLabel="Tạo YCMH"
          saveEditLabel="Lưu thay đổi"
          onSave={showSave ? handleSave : undefined}
        />
      )}
    >
      <div className={[df.section, compact.headerCompactSectionClass].filter(Boolean).join(' ')}>
        <div className={df.sectionTitleRow}>
          <h2 className={df.sectionTitle}>Thông tin chung</h2>
          <button
            type="button"
            className={df.headerToggleBtn}
            data-testid={`erp-mh-ycmh-form-header-${headerExpanded ? 'collapse' : 'expand'}`}
            aria-expanded={headerExpanded}
            onClick={() => setHeaderExpanded(v => !v)}
          >
            <span className={df.headerToggleIcon} aria-hidden>
              <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
            </span>
            {headerExpanded ? 'Thu gọn' : 'Mở rộng'}
          </button>
        </div>
        <div className={df.headerFieldsFlow}>
          <div className={df.row4}>
            <div className={compact.fieldClass(compact.compactHideClass(true))}>
              <label className={df.label}>Ngày yêu cầu</label>
              <Input type="date" value={requestDate} onChange={e => setRequestDate(e.target.value)} disabled={!canWrite} />
            </div>
            <div className={compact.fieldClass(compact.compactHideClass(true))}>
              <label className={df.label}>{DEPARTMENT_FIELD_LABEL}</label>
              <Select value={departmentId} onChange={e => setDepartmentId(e.target.value)} options={deptOptions} disabled={!canWrite} />
            </div>
            <div className={[df.spanCol2, compact.compactHideClass(false)].filter(Boolean).join(' ')}>
              <label className={df.label}>Mô tả</label>
              <Input value={description} onChange={e => setDescription(e.target.value)} disabled={!canWrite} />
            </div>
          </div>
        </div>
      </div>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết vật tư</h2>
        <div className={df.tableWrapper}>
          <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
            <thead>
              <tr>
                <MaterialLineTableHeaders /><th>ĐVT</th><th className={df.thAmount}>SL</th>
                <th className={df.thAmount}>Giá dự kiến</th><th>Ghi chú</th><th className={df.thDel} />
              </tr>
            </thead>
            <tbody>
              {lines.map((line, idx) => (
                <tr key={idx} {...lineRowProps(idx)}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    disabled={!canWrite}
                    onSelect={m => updateLine(idx, {
                      materialCode: m.code,
                      materialName: m.name,
                      unitCode: m.unitCode ?? line.unitCode,
                    })}
                    onClear={() => updateLine(idx, { materialCode: '', materialName: '' })}
                  />
                  <td data-label="ĐVT"><Input value={line.unitCode} onChange={e => updateLine(idx, { unitCode: e.target.value })} disabled={!canWrite} /></td>
                  <td data-label="SL" className={df.tdAmount}><Input type="number" value={String(line.quantity)} onChange={e => updateLine(idx, { quantity: Number(e.target.value) })} disabled={!canWrite} /></td>
                  <td data-label="Giá dự kiến" className={df.tdAmount}><Input type="number" value={String(line.estimatedPrice)} onChange={e => updateLine(idx, { estimatedPrice: Number(e.target.value) })} disabled={!canWrite} /></td>
                  <td data-label="Ghi chú"><Input value={line.note ?? ''} onChange={e => updateLine(idx, { note: e.target.value })} disabled={!canWrite} /></td>
                  <td className={df.tdDel} data-label="">
                    <button type="button" className={df.btnDeleteLine} onClick={() => removeLine(idx)} title="Xóa dòng" disabled={!canWrite}>×</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <MaterialLinesGridActions
          canEdit={!!showSave}
          onAddLine={addLine}
          onCopyLine={copyLine}
          linesCount={lines.length}
        />
      </div>
    </VoucherDocumentFormShell>
  );
};

export default YcmhFormPage;
